#include <stdio.h>
struct ins {
    int c[10];
    int a;
};
int main() {
    struct ins ob1 = {0}, ob2 = {0};
    int i;
    for (i = 0; i < 10; i += 2) {
        ob1.c[i] = i;
        ob2.c[i] = i + i;
    }
    for (i = 0; i < 10; i += 2) {
        ob1.a = ob1.a + ob1.c[i];
        ob2.a = ob2.a + ob2.c[i];
    }
    printf("%d\n", ob1.a + ob2.a);
}
```

